public Complex tanh() {
    if (isNaN) {
        return NaN;
    }
    double real2 = 2.0 * real;
    double imaginary2 = 2.0 * imaginary;
    double cosh2a = FastMath.cosh(real2);
    double cos2b = FastMath.cos(imaginary2);
    double sinh2a = FastMath.sinh(real2);
    double sin2b = FastMath.sin(imaginary2);
    double d = cosh2a + cos2b;

    if (Double.isInfinite(real) && Double.isFinite(imaginary)) {
        return createComplex(FastMath.signum(real), 0);
    }
    if (Double.isInfinite(imaginary) && Double.isFinite(real)) {
        return NaN;
    }
    if (Double.isInfinite(real) && Double.isInfinite(imaginary)) {
        return NaN;
    }
    if (Double.isInfinite(d)) {
        return createComplex(FastMath.signum(sinh2a), 0);
    }

    return createComplex(sinh2a / d, sin2b / d);
}

public Complex tanh() {
    if (isNaN) {
        return NaN;
    }
    double real2 = 2.0 * real;
    double imaginary2 = 2.0 * imaginary;

    // Scale down large values to prevent overflow and improve numerical stability
    final double scaleThreshold = 709.0; // Threshold before double overflow in sinh/cosh
    boolean scaled = false;
    if (Math.abs(real2) > scaleThreshold) {
        real2 /= 2.0;
        imaginary2 /= 2.0;
        scaled = true;
    }

    double coshReal2 = FastMath.cosh(real2);
    double cosImaginary2 = FastMath.cos(imaginary2);
    double d = coshReal2 + cosImaginary2;

    if (Double.isInfinite(d) || d == 0.0) {
        return createComplex(FastMath.copySign(1.0, real), 0.0);
    }

    double sinhReal2 = FastMath.sinh(real2);
    double sinImaginary2 = FastMath.sin(imaginary2);

    if (scaled) {
        sinhReal2 *= 2.0;
        sinImaginary2 *= 2.0;
    }

    return createComplex(sinhReal2 / d,
                         sinImaginary2 / d);
}

